127	    if (diff < 60000) return `${Math.floor(diff / 1000)}s ago`;
128	    if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
129	    if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
