.company-profile-tabs {
  display: flex;
  gap: 0;
  padding: 0 var(--sp-4);
  border-bottom: 1px solid var(--border);
  background: var(--bg-surface);
}

.cp-tab {
  padding: var(--sp-2) var(--sp-4);
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  font-weight: 500;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  border: none;
  background: none;
  cursor: pointer;
  position: relative;
  transition: color var(--duration-fast);
}

.cp-tab:hover {
  color: var(--text-secondary);
}

.cp-tab.active {
  color: var(--blue);
}

.cp-tab.active::after {
  content: '';
  position: absolute;
  bottom: -1px;
  left: 0;
  right: 0;
  height: 2px;
  background: var(--blue);
  border-radius: 1px 1px 0 0;
}

.company-profile-body {
  padding: var(--sp-4);
}

/* Loading skeleton */
.cp-loading-row {
  margin-bottom: var(--sp-2);
}

.cp-loading-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--sp-3);
  margin-top: var(--sp-3);
}

/* Error state */
.cp-error {
  text-align: center;
  padding: var(--sp-4) 0;
  color: var(--text-secondary);
}

.cp-error-icon {
