  height: 40px;
  border-radius: 50%;
  background: var(--red-bg);
  border: 1px solid var(--red-border);
  color: var(--red);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 18px;
  margin: 0 auto var(--sp-3);
}

.cp-error p {
  font-size: 14px;
  font-weight: 600;
